resource "pagerduty_escalation_policy" "payments" {
  name      = "Payments escalation"
  num_loops = 2 # loop the chain twice, then stop dead-ending

  rule {
    escalation_delay_in_minutes = 6 # ack window before next level
    target {
      type = "schedule_reference"
      id   = pagerduty_schedule.payments_primary.id
    }
  }

  rule {
    escalation_delay_in_minutes = 6
    target {
      type = "schedule_reference"
      id   = pagerduty_schedule.payments_secondary.id
    }
  }

  rule {
    escalation_delay_in_minutes = 10
    target {
      type = "user_reference"
      id   = var.engineering_manager_id # final catch-all
    }
  }
}
